const { run_id, start_ts, lectura, analisis } = $input.item.json;
const e3_start = new Date().toISOString();
// Clave de idempotencia para evitar duplicados en reintentos
const idempotency_key = `${lectura.sensor_id}-${lectura.timestamp}`;
console.log(JSON.stringify({ run_id, etapa: 'E3_persistencia_iot', status: 'preparando', idempotency_key, e3_start }));
return [{ json: { run_id, start_ts, e3_start, lectura, analisis, idempotency_key } }];

const input = $('E3 - Preparar para persistencia').item.json;
const dbResult = $input.item.json;
const e3_end = new Date().toISOString();
const duracion_ms = new Date(e3_end) - new Date(input.e3_start);
console.log(JSON.stringify({
  run_id: input.run_id, etapa: 'E3_persistencia_iot',
  status: 'ok', idempotency_key: input.idempotency_key,
  registro_id: dbResult.id || 'ya-existia',
  e3_start: input.e3_start, e3_end, duracion_ms
}));
return [{ json: { run_id: input.run_id, start_ts: input.start_ts, lectura: input.lectura, analisis: input.analisis, registro_id: dbResult.id || null } }];
